import re, os
for d in ['mapping/concepts', 'mapping/entities', 'mapping/syntheses']:
  for f in sorted(os.listdir(d)):
    if not f.endswith('.md'): continue
    p = os.path.join(d, f)
    text = open(p, encoding='utf-8').read()
    text = re.sub(r'```.*?```', '', text, flags=re.S)
    text = re.sub(r'`[^`]*`', '', text)
    def keep_disp(m):
        inner = m.group(1)
        if '|' in inner: inner = inner.split('|',1)[1]
        return inner
    text = re.sub(r'\[\[([^\]]+)\]\]', keep_disp, text)
    issues = []
    for i, line in enumerate(text.split('\n'), 1):
        for m in re.finditer(r'([一-鿿])([,;?!])|([,;?!])([一-鿿])', line):
            issues.append('L%d ADJ: %s' % (i, line[max(0,m.start()-6):m.end()+6]))
        # colon: only flag CJK on left
        for m in re.finditer(r'[一-鿿]:', line):
            issues.append('L%d COLON: %s' % (i, line[max(0,m.start()-6):m.end()+6]))
        if '"' in line:
            for m in re.finditer(r'"[^"]*"', line):
                surround = line[max(0,m.start()-2):min(len(line),m.end()+2)]
                if re.search(r'[一-鿿]', surround):
                    issues.append('L%d STRAIGHTQ: %s' % (i, surround))
        if re.search(r'(?<!—)—(?!—)', line):
            issues.append('L%d SINGLE-EM: %s' % (i, line.strip()[:80]))
        if re.search(r'(?<!\.)\.{3}(?!\.)', line):
            ctx = line[max(0,line.find('...')-5):line.find('...')+8]
            if re.search(r'[一-鿿]', ctx):
                issues.append('L%d ELLIPSIS: %s' % (i, ctx))
        # paren with CJK adjacent
        for m in re.finditer(r'[一-鿿]\(|\)[一-鿿]', line):
            issues.append('L%d PAREN: %s' % (i, line[max(0,m.start()-6):m.end()+6]))
    if issues:
        print('=== %s ===' % p)
        for x in issues[:20]: print(' ', x)
        if len(issues) > 20: print(' (+%d more)' % (len(issues)-20))

